        fetchModels(parentWin) {
            const { apiType, apiKey, baseUrl } = this.config;
            const msgBox = parentWin.document.getElementById('cfg-msg');
            const select = parentWin.document.getElementById('cfg-model-select');
            const input = parentWin.document.getElementById('cfg-model');
            if(!apiKey) { msgBox.textContent = "❌ 请先填写API Key"; return; }
            msgBox.textContent = "⏳ 扫描模型中...";
            (async () => {
                try {
                    let url = baseUrl.replace(/\/$/, '');
                    let fetchedModels = [];
                    if (apiType === 'openai') {
                        if (!url.endsWith('/v1')) url += '/v1';
                        const res = await fetch(`${url}/models`, { headers: { 'Authorization': `Bearer ${apiKey}` } });
                        const data = await res.json();
                        if(data.data) fetchedModels = data.data.map(m => m.id);
                    } else {
                        const res = await fetch(`${url}/v1beta/models?key=${apiKey}`);
                        const data = await res.json();
                        if(data.models) fetchedModels = data.models.map(m => m.name.replace('models/', ''));
                    }
                    if(fetchedModels.length > 0) {
                        select.innerHTML = `<option value="">选择模型 (${fetchedModels.length})</option>` + fetchedModels.map(m => `<option value="${m}">${m}</option>`).join('');
                        select.style.display = 'block';
                        select.onchange = () => { if(select.value) input.value = select.value; };
                        msgBox.textContent = "✅ 扫描完成";
                    } else { msgBox.textContent = "⚠️ 未找到模型"; }
                } catch(e) { console.error(e); msgBox.textContent = "❌ 扫描失败: " + e.message; }
            })();
        },

        sendToSillyTavern(parentWin, text, autoSend = true) {
            const stInput = parentWin.document.getElementById('send_textarea');
            const stBtn = parentWin.document.getElementById('send_but');
            let inputEl = stInput || parentWin.document.querySelector('#chat_input, textarea');

            if (inputEl && stBtn) {
                const nativeInputValueSetter = Object.getOwnPropertyDescriptor(window.HTMLTextAreaElement.prototype, 'value').set;
                if(nativeInputValueSetter) { nativeInputValueSetter.call(inputEl, text); } else { inputEl.value = text; }
                inputEl.dispatchEvent(new Event('input', { bubbles: true }));
                inputEl.dispatchEvent(new Event('change', { bubbles: true }));
                if (autoSend) {
                    setTimeout(() => stBtn.click(), 100);
                } else {
                    inputEl.focus();
                }
            } else {
                alert("找不到SillyTavern输入框");
            }
        },

        gmFetch(details) {
            return new Promise((resolve, reject) => {
                if (typeof GM_xmlhttpRequest !== 'undefined') {
                    GM_xmlhttpRequest({
                        method: details.method,
                        url: details.url,
                        headers: details.headers,
                        data: details.body,
                        onload: (response) => {
                            if (response.status >= 200 && response.status < 300) {
                                resolve(response.responseText);
                            } else {
                                reject(new Error(`${response.status} ${response.statusText}\n${response.responseText}`));
                            }
                        },
                        onerror: (err) => reject(new Error("Network Error: " + err)),
                        ontimeout: () => reject(new Error("Timeout"))
                    });
                }
                else if (typeof GM !== 'undefined' && GM.xmlHttpRequest) {
                    GM.xmlHttpRequest({
                        method: details.method,
                        url: details.url,
                        headers: details.headers,
                        data: details.body,
                        onload: (response) => {
                            if (response.status >= 200 && response.status < 300) {
                                resolve(response.responseText);
                            } else {
                                reject(new Error(`${response.status} ${response.statusText}\n${response.responseText}`));
                            }
                        },
                        onerror: (err) => reject(new Error("Network Error")),
                        ontimeout: () => reject(new Error("Timeout"))
                    });
                }
                else {
                    fetch(details.url, {
                        method: details.method,
                        headers: details.headers,
                        body: details.body
                    })
                    .then(async (response) => {
                        const text = await response.text();
                        if (response.ok) {
                            resolve(text);
                        } else {
                            reject(new Error(`${response.status} ${response.statusText}\n${text}`));
                        }
                    })
                    .catch(err => reject(new Error("Fetch/CORS Error: " + err.message)));
                }
            });
        },

        async callUniversalAPI(parentWin, text, options = {}) {
            const { isChat = false, systemPrompt = null } = options;
            const { apiType, apiKey, baseUrl, model } = this.config;
            if (!apiKey) { console.error("❌ 未配置API Key"); return null; }

            let url = baseUrl.replace(/\/$/, '');
            let finalSystemPrompt = systemPrompt || getDynamicPersona();
            finalSystemPrompt += `\n${JAILBREAK}`;

            try {
                let fetchUrl, fetchBody, fetchHeaders;
                const MAX_TOKENS = 4096;

                if (apiType === 'openai') {
                    if (!url.endsWith('/v1')) url += '/v1';
                    fetchUrl = `${url}/chat/completions`;
                    let msgs = [];
                    if(isChat) {
                        const safeHistory = panelChatHistory.slice(-10);
                        msgs = [{ role: 'system', content: finalSystemPrompt }, ...safeHistory, { role: 'user', content: text }];
                    } else {
                        msgs = [{ role: 'user', content: finalSystemPrompt + "\n" + text }];
                    }
                    fetchHeaders = { 'Content-Type': 'application/json', 'Authorization': `Bearer ${apiKey}` };
                    fetchBody = JSON.stringify({ model: model, messages: msgs, max_tokens: MAX_TOKENS, temperature: 0.9 });
                } else {
                    let modelId = model;
                    if (!modelId.startsWith('models/') && !url.includes(modelId)) modelId = 'models/' + modelId;
                    fetchUrl = `${url}/v1beta/${modelId}:generateContent?key=${apiKey}`;
                    let historyText = panelChatHistory.slice(-5).map(h => `${h.role}: ${h.content}`).join('\n');
                    let promptText = isChat ? (finalSystemPrompt + "\n[HISTORY]\n" + historyText + "\n[/HISTORY]\nUser: " + text) : (finalSystemPrompt + "\n" + text);
                    fetchHeaders = { 'Content-Type': 'application/json' };
                    fetchBody = JSON.stringify({ contents: [{ role: 'user', parts: [{ text: promptText }] }], generationConfig: { maxOutputTokens: MAX_TOKENS } });
                }

                const responseText = await this.gmFetch({
                    method: 'POST',
                    url: fetchUrl,
                    headers: fetchHeaders,
                    body: fetchBody
                });

                const data = JSON.parse(responseText);
                let reply = apiType === 'openai' ? data.choices?.[0]?.message?.content : data.candidates?.[0]?.content?.parts?.[0]?.text;
                reply = reply?.trim();

                if (isChat && reply) {
                    panelChatHistory.push({role:'user', content:text});
                    panelChatHistory.push({role:'minori', content:reply});
                    saveChat();
                }
                return reply;
            } catch(e) {
                console.error("API Error:", e);
                return null;
            }
        },

