<script>
    // 在页面加载后绑定所有事件，这种方式在聊天框环境中最稳定

    // 绑定多选框效果
    document.querySelectorAll('.check-label input').forEach(input => {
        input.addEventListener('change', function() {
            if(this.checked) this.parentElement.classList.add('checked');
            else this.parentElement.classList.remove('checked');
        });
    });

    // 绑定属性点数实时计算
    const MAX_POINTS = 75;
    function calcPoints() {
        const inputs = document.querySelectorAll('.stat-input');
        let used = 0;
        inputs.forEach(inp => used += parseInt(inp.value || 0));

        const remaining = MAX_POINTS - used;
        const display = document.getElementById('points-val');
        if(display) {
            display.innerText = remaining;
            if(remaining < 0) {
                display.className = 'points-low';
                display.innerText = remaining + " (已触发Minori算力干预!)";
            } else {
                display.className = 'points-ok';
            }
        }
    }

    document.querySelectorAll('.stat-input').forEach(input => {
        input.addEventListener('input', calcPoints);
    });
    calcPoints(); // 初始计算一次

    // 绑定职业下拉菜单
    const classSelect = document.getElementById('char_class_select');
    if(classSelect) {
        classSelect.addEventListener('change', function() {
            const val = this.value;
            if(val) {
                const tagInput = document.getElementById('char_tags');
                if(tagInput) {
                    let current = tagInput.value;
                    if (current === "") tagInput.value = val.split(' ')[0];
                    else if (!current.includes(val.split(' ')[0])) tagInput.value = current + ", " + val.split(' ')[0];
                }
            }
        });
    }

    // 绑定世界下拉菜单，动态显示隐藏输入框
    const worldSelect = document.getElementById('world_select');
    if(worldSelect) {
        worldSelect.addEventListener('change', function() {
            const box = document.getElementById('world_desc_box');
            const customBox = document.getElementById('custom_world_box');
            const val = this.value;

            if (val === "custom") {
                if(customBox) customBox.style.display = 'block';
                if(box) box.style.display = 'none';
                return;
            } else {
                if(customBox) customBox.style.display = 'none';
            }

            if (!val) {
                if(box) box.style.display = 'none';
                return;
            }

            const parts = val.split('|');
            const name = parts[0];
            const diff = parts[1];
            const tags = parts[2];

            if(box) {
                box.style.display = 'block';
                box.innerHTML = `
                    <strong>目标游乐场:</strong> ${name}<br>
                    <strong>主神判定难度:</strong> <span style="color:var(--danger)">${diff}</span><br>
                    <strong>Minori已解析法则:</strong> ${tags}
                `;
            }
        });

        // 初始触发一次以判断默认状态
        worldSelect.dispatchEvent(new Event('change'));
    }

    // 提示弹窗
    function showToast() {
        const t = document.getElementById('toast-msg');
        if(t) {
            t.classList.add('show');
            setTimeout(() => t.classList.remove('show'), 2500);
        }
    }

    // 复制到输入框功能
    function copyToInput(text) {
        try {
            if (window.parent && window.parent.$) {
                const $ta = window.parent.$('#send_textarea');
                if ($ta.length > 0) {
                    $ta.val(text);
                    $ta[0].dispatchEvent(new Event('input', { bubbles: true }));
                    showToast();
                    return;
                }
            }
            const ta = document.getElementById('send_textarea');
            if(ta) {
                ta.value = text;
                ta.dispatchEvent(new Event('input', { bubbles: true }));
                showToast();
            } else {
                alert("找不到底部的输入框，可能是在预览模式下。");
            }
        } catch (e) {
            console.error('载入指令错误:', e);
            alert("填充失败，请检查环境。");
        }
    }

    // 绑定生成按钮
    const generateBtn = document.getElementById('generate_btn');
    if(generateBtn) {
        generateBtn.addEventListener('click', function() {
            const v = (id) => {
                const el = document.getElementById(id);
                return el ? (el.value.trim() || "未知") : "未知";
            };

            let skills = [];
            document.querySelectorAll('.check-label input:checked').forEach(cb => {
                skills.push(`    - ${cb.value}`);
            });
            const skillStr = skills.length > 0 ? skills.join('\n') : "    - 暂无显著技能";

            const wSelect = document.getElementById('world_select');
            const worldVal = wSelect ? wSelect.value : "";
            let worldBlock = "";
            let worldName = "随机位面";

            if (worldVal === "custom") {
                const cInput = document.getElementById('custom_world_input');
                worldName = cInput ? (cInput.value.trim() || "未知自定义世界") : "未知自定义世界";
                worldBlock = `
  初始世界锚定:
    目标位面: ${worldName}
    难度: 未知(由Minori保驾护航)
    Minori备注: "主人亲自挑选的地方呢！无论哪里Minori都会陪你一起去哒！"`;
            } else if (worldVal) {
                const parts = worldVal.split('|');
                worldName = parts[0];
                worldBlock = `
  初始世界锚定:
    目标位面: ${parts[0]}
    难度: ${parts[1]}
    关键要素: ${parts[2]}
    Minori备注: "已锁定坐标！新手大礼包将适配该世界规则发放。"`;
            } else {
                worldBlock = `
  初始世界锚定:
    目标位面: 随机分配
    状态: 等待Minori抽奖
    Minori备注: "欸？主人喜欢惊喜吗？那Minori就闭着眼睛选一个咯！"`;
            }

            const name = v('char_name');
            const template = `<character_information character="${name}">
核心身份：
  名称：${name}
  性别：${v('char_gender')}
  年龄：${v('char_age')}
  标签：${v('char_tags')}

背景：
  出身：主神空间新人
  所处环境：维度轮回空间 -> ${worldName}

外貌描写：
  整体印象：${v('appearance').split('，')[0] || "神情戒备"}
  体型身材：力量${v('str')}，敏捷${v('dex')}，体质${v('con')}
  面部特征：${v('appearance')}
  穿着风格：${v('clothing')}

性格：
  MBTI类型：${v('mbti')}
  核心动机：${v('motivation')}

能力：
  基础面板: [STR:${v('str')}, DEX:${v('dex')}, CON:${v('con')}, INT:${v('int')}, WIS:${v('wis')}, CHA:${v('cha')}]
  擅长领域：
${skillStr}
  特殊能力：
${v('special_abilities') ? '    - ' + v('special_abilities').replace(/\n/g, '\n    - ') : '    - 暂无强化'}
${worldBlock}
</character_information>`;

            // 直接注入到对话框
            copyToInput(template);
        });
    }
</script>

</body>
