    <style>
        :root {
            --sys-bg: rgba(30, 20, 25, 0.85);
            --sys-border: #ffb6c1;
            --sys-glow: #ff69b4;
            --sys-danger: #ff4500;
            --sys-text: #fff0f5;
            --sys-dim: #dda0dd;
            --minori-pink: #ff1493;
            --minori-bg: rgba(255, 105, 180, 0.15);
            --gold: #ffd700;
        }

        body { margin: 0; padding: 0; background: transparent; }

        .dimension-system-panel {
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            background: var(--sys-bg);
            border: 2px solid var(--sys-border);
            box-shadow: 0 0 20px rgba(255, 105, 180, 0.2), inset 0 0 15px rgba(255, 20, 147, 0.1);
            border-radius: 16px;
            padding: 15px;
            color: var(--sys-text);
            max-width: 450px;
            margin: 15px auto;
            position: relative;
            overflow: hidden;
            font-size: 13px;
            backdrop-filter: blur(8px);
            -webkit-backdrop-filter: blur(8px);
        }

        .dimension-system-panel::before {
            content: ""; position: absolute; top: 0; left: 0; right: 0; height: 3px;
            background: linear-gradient(90deg, transparent, var(--sys-glow), transparent);
            opacity: 0.6; animation: scanline 3s ease-in-out infinite; z-index: 10; pointer-events: none;
        }
        @keyframes scanline { 0% { transform: translateY(-10px); } 100% { transform: translateY(1000px); } }

        .panel-header {
