            padding: 3px 8px; border-radius: 12px; display: flex; align-items: center; gap: 4px;
        }
        .danger-tag { color: var(--sys-danger); border-color: rgba(255, 69, 0, 0.4); background: rgba(255, 69, 0, 0.1); }

        .tab-nav {
            display: flex; margin-bottom: 15px; gap: 6px;
            background: rgba(0,0,0,0.3); border-radius: 10px; padding: 5px;
        }
        .tab-btn {
            flex: 1; background: transparent; border: none; padding: 6px 0;
            color: var(--sys-dim); cursor: pointer; font-family: inherit; font-size: 12px; font-weight: bold;
            transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1); border-radius: 8px;
        }
        .tab-btn:hover { color: #fff; background: rgba(255, 182, 193, 0.1); }
        .tab-btn.active {
            color: #fff; background: linear-gradient(135deg, var(--sys-glow), var(--minori-pink));
            box-shadow: 0 4px 10px rgba(255, 20, 147, 0.3); text-shadow: 0 1px 2px rgba(0,0,0,0.5);
        }
        .tab-btn.minori-tab { color: var(--sys-glow); }
