        .tab-content.active { display: block; }
        @keyframes slideUp { from { opacity: 0; transform: translateY(8px); } to { opacity: 1; transform: translateY(0); } }

        .data-row { display: flex; justify-content: space-between; margin-bottom: 8px; align-items: center;}
        .data-label { color: var(--sys-dim); font-size: 12px; font-weight: bold; }
        .data-value { font-weight: bold; color: #fff; }
        .gold-text { color: var(--gold); text-shadow: 0 0 5px rgba(255,215,0,0.5); }

        .bar-container {
            width: 100%; height: 8px; background: rgba(0,0,0,0.5);
            border: 1px solid var(--sys-border); border-radius: 4px; margin-top: 4px; overflow: hidden;
        }
        .hp-bar { height: 100%; background: linear-gradient(90deg, #ff4e50, #f9d423); transition: width 0.4s; }
        .energy-bar { height: 100%; background: linear-gradient(90deg, #fbc2eb, #a6c1ee); transition: width 0.4s; box-shadow: 0 0 10px rgba(251, 194, 235, 0.8); }
        .exp-bar { height: 100%; background: linear-gradient(90deg, #4facfe, #00f2fe); transition: width 0.4s; box-shadow: 0 0 10px rgba(79, 172, 254, 0.6); }

        .attr-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 8px; margin-top: 10px; }
        .attr-box {
            background: var(--minori-bg); border: 1px solid rgba(255, 105, 180, 0.3);
            border-radius: 8px; padding: 6px; text-align: center; transition: transform 0.2s;
        }
        .attr-box:hover { transform: translateY(-2px); box-shadow: 0 4px 8px rgba(255, 105, 180, 0.2); }
        .attr-name { font-size: 10px; color: var(--sys-dim); font-weight: bold; margin-bottom: 2px;}
        .attr-val { font-size: 18px; font-weight: 900; font-family: 'Courier New', monospace; color: #fff; text-shadow: 0 0 8px var(--sys-glow); line-height: 1;}
        .attr-mod { font-size: 10px; color: var(--sys-border); background: rgba(0,0,0,0.3); border-radius: 8px; display: inline-block; padding: 1px 6px; margin-top: 2px;}

        .asset-container { display: flex; flex-wrap: wrap; gap: 8px; margin-top: 10px; }
        .asset-badge {
            font-size: 11px; background: rgba(0,0,0,0.4); border: 1px solid var(--gold);
            padding: 4px 10px; border-radius: 12px; display: flex; align-items: center; gap: 4px;
        }

        .interact-row { display: flex; gap: 10px; margin-bottom: 10px; }
        .cyber-input {
            flex: 1; padding: 10px; background: rgba(0, 0, 0, 0.3); border: 2px solid var(--sys-border);
            border-radius: 8px; color: #fff; font-size: 12px; font-family: inherit; transition: all 0.3s;
        }
        .cyber-input:focus { outline: none; border-color: var(--sys-glow); box-shadow: 0 0 10px rgba(255, 105, 180, 0.4); }

        .cyber-select {
            width: 85px; padding: 10px; background: rgba(0, 0, 0, 0.3); border: 2px solid var(--sys-border);
            border-radius: 8px; color: var(--sys-glow); font-size: 12px; cursor: pointer; font-weight: bold;
        }
        .cyber-select option { background: var(--sys-bg); color: #fff; }

        .dice-btn {
            width: 100%; padding: 12px; background: linear-gradient(135deg, var(--sys-glow), var(--minori-pink));
            border: none; border-radius: 8px; color: #fff; font-size: 14px; font-weight: 900; letter-spacing: 2px;
            cursor: pointer; transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
            box-shadow: 0 4px 15px rgba(255, 20, 147, 0.4);
        }
        .dice-btn:hover { transform: translateY(-2px); box-shadow: 0 6px 20px rgba(255, 20, 147, 0.6); filter: brightness(1.1); }
        .dice-btn:disabled { opacity: 0.8; filter: grayscale(50%); cursor: not-allowed; transform: none; box-shadow: none; }

        .quick-actions {
            display: grid; grid-template-columns: repeat(4, 1fr); gap: 8px;
            padding-top: 15px; margin-top: 15px; border-top: 2px dotted rgba(255, 182, 193, 0.3);
        }
        .quick-btn {
            background: rgba(0, 0, 0, 0.3); border: 1px solid var(--sys-border); color: var(--sys-text);
            padding: 8px 4px; border-radius: 8px; text-align: center; cursor: pointer; font-size: 10px;
            font-weight: bold; transition: all 0.3s; display: flex; flex-direction: column; align-items: center; gap: 5px;
        }
        .quick-btn i { font-size: 16px; color: var(--sys-dim); transition: all 0.3s; }
        .quick-btn:hover { background: var(--minori-bg); border-color: var(--sys-glow); color: #fff; transform: translateY(-2px); }
        .quick-btn:hover i { color: var(--sys-glow); text-shadow: 0 0 5px var(--sys-glow); }

        .quick-btn.minori-action { border-color: var(--minori-pink); background: rgba(255, 20, 147, 0.1);}
        .quick-btn.minori-action i { color: var(--minori-pink); }
        .quick-btn.minori-action:hover { background: var(--minori-pink); color: #fff; }
        .quick-btn.minori-action:hover i { color: #fff; }

        .quick-btn.harem-action { border-color: #ff3366; background: rgba(255, 51, 102, 0.15); position: relative; overflow: hidden;}
        .quick-btn.harem-action i { color: #ff3366; animation: heartbeat 1.5s infinite; }
        .quick-btn.harem-action:hover { background: #ff3366; color: #fff; border-color:#ff99aa; box-shadow: 0 0 15px rgba(255, 51, 102, 0.6);}
        .quick-btn.harem-action:hover i { color: #fff; }
        @keyframes heartbeat { 0%, 100% { transform: scale(1); } 50% { transform: scale(1.2); } }

        .harem-modal {
            display: none; position: absolute; top: 0; left: 0; width: 100%; height: 100%;
            background: rgba(15, 10, 15, 0.95); z-index: 50; flex-direction: column;
            padding: 20px; box-sizing: border-box; backdrop-filter: blur(5px);
            border-radius: 16px; animation: glitch-in 0.3s ease-out;
        }
        @keyframes glitch-in { 0% { opacity: 0; transform: scale(1.05); filter: hue-rotate(90deg); } 100% { opacity: 1; transform: scale(1); } }
        .modal-title { color: #ff3366; font-size: 16px; font-weight: 900; margin-bottom: 15px; border-bottom: 1px dashed #ff3366; padding-bottom: 5px; }
        .modal-close { position: absolute; right: 15px; top: 15px; color: #aaa; cursor: pointer; font-size: 18px; }
        .modal-close:hover { color: #fff; }
        .modal-btn { background: #ff3366; color: #fff; border: none; padding: 10px; border-radius: 8px; font-weight: bold; cursor: pointer; margin-top: 15px; transition: 0.2s; }
        .modal-btn:hover { background: #ff1a53; box-shadow: 0 0 15px rgba(255, 51, 102, 0.5); }

        .toast {
            position: absolute; bottom: 20px; left: 50%; transform: translateX(-50%);
            background: rgba(255, 20, 147, 0.9); border: 2px solid #fff;
            color: #fff; padding: 10px 20px; border-radius: 20px; font-size: 13px; font-weight: bold;
            opacity: 0; pointer-events: none; transition: opacity 0.3s; z-index: 100;
        }
        .toast.show { opacity: 1; }

        .cyber-anim-overlay {
            position: absolute; top: 0; left: 0; width: 100%; height: 100%;
            background: rgba(20, 10, 15, 0.92); z-index: 60;
            display: none; flex-direction: column; justify-content: center; align-items: center;
            backdrop-filter: blur(5px); border-radius: 16px;
            opacity: 0; transition: opacity 0.3s;
        }
        .cyber-anim-overlay.show { display: flex; opacity: 1; }

        .cyber-radar {
            position: relative; width: 120px; height: 120px;
            display: flex; justify-content: center; align-items: center; margin-bottom: 15px;
        }
        .radar-outer { position: absolute; font-size: 120px; color: rgba(255, 105, 180, 0.3); animation: spin-radar 2s linear infinite; }
        .radar-inner { position: absolute; font-size: 70px; color: rgba(255, 20, 147, 0.5); animation: spin-radar 1.5s linear infinite reverse; }
        @keyframes spin-radar { 100% { transform: rotate(360deg); } }

        .cyber-number-box {
            position: relative; z-index: 2; background: var(--sys-bg);
            width: 60px; height: 60px; border-radius: 50%;
            display: flex; justify-content: center; align-items: center;
            border: 2px solid var(--minori-pink);
            box-shadow: 0 0 15px var(--sys-glow), inset 0 0 10px rgba(255, 20, 147, 0.4);
        }
        .cyber-number-text {
            font-family: 'Courier New', monospace; font-size: 28px; font-weight: 900;
            color: #fff; text-shadow: 0 0 8px var(--minori-pink); line-height: 1;
        }
        .cyber-subtitle {
            font-size: 15px; font-weight: bold; color: var(--sys-glow);
            letter-spacing: 2px; text-shadow: 0 0 8px rgba(255, 105, 180, 0.6);
            animation: blink-text 1s infinite alternate;
        }
        @keyframes blink-text { 0% { opacity: 0.6; } 100% { opacity: 1; text-shadow: 0 0 15px var(--sys-glow); } }

        /* 音乐播放器专用按钮调整 */
        .music-btn {
            background: transparent; border: 1px solid var(--minori-pink); color: var(--sys-text);
            padding: 4px 10px; border-radius: 6px; cursor: pointer; font-size: 12px;
            transition: all 0.3s;
        }
        .music-btn:hover { background: rgba(255, 20, 147, 0.2); color: #fff; box-shadow: 0 0 8px rgba(255, 20, 147, 0.5); }
    </style>
</head>
<body>
    <div class="dimension-system-panel" id="main-status-panel">

        <div class="cyber-anim-overlay" id="dice-anim-overlay">
