                    <span class="data-value" style="color: #4facfe;"><span id="val-exp-cur">0</span> / <span id="val-exp-max">100</span></span>
                </div>
                <div class="bar-container" style="border-color: rgba(79, 172, 254, 0.4);"><div class="exp-bar" id="ui-exp-bar" style="width: 0%;"></div></div>
            </div>

            <div class="data-row" style="display: block;">
                <div style="display: flex; justify-content: space-between; margin-bottom: 4px;">
