            </div>

            <div class="attr-grid">
                <div class="attr-box"><div class="attr-name">力量 STR</div><div class="attr-val" id="val-str">10</div><div class="attr-mod" id="mod-str">+0</div></div>
                <div class="attr-box"><div class="attr-name">敏捷 DEX</div><div class="attr-val" id="val-dex">10</div><div class="attr-mod" id="mod-dex">+0</div></div>
                <div class="attr-box"><div class="attr-name">体质 CON</div><div class="attr-val" id="val-con">10</div><div class="attr-mod" id="mod-con">+0</div></div>
                <div class="attr-box"><div class="attr-name">智力 INT</div><div class="attr-val" id="val-int">10</div><div class="attr-mod" id="mod-int">+0</div></div>
                <div class="attr-box"><div class="attr-name">感知 WIS</div><div class="attr-val" id="val-wis">10</div><div class="attr-mod" id="mod-wis">+0</div></div>
                <div class="attr-box"><div class="attr-name">魅力 CHA</div><div class="attr-val" id="val-cha">10</div><div class="attr-mod" id="mod-cha">+0</div></div>
            </div>
            <div class="data-row" style="margin-top: 10px;">
                <span class="data-label">护甲防御: <span class="data-value" id="val-ac" style="color:var(--gold);">10</span></span>
