        <div id="tab-gear" class="tab-content">
            <div class="data-row"><span class="data-label">武装:</span><span class="data-value" id="val-weapon">--</span></div>
            <div class="data-row"><span class="data-label">外装:</span><span class="data-value" id="val-armor">--</span></div>
