            <div class="asset-container">
                <div class="asset-badge"><span class="gold-text">D:</span> <span id="val-d">0</span></div>
                <div class="asset-badge"><span class="gold-text">C:</span> <span id="val-c">0</span></div>
                <div class="asset-badge"><span class="gold-text">B:</span> <span id="val-b">0</span></div>
                <div class="asset-badge"><span class="gold-text">A:</span> <span id="val-a">0</span></div>
                <div class="asset-badge"><span class="gold-text">S:</span> <span id="val-s">0</span></div>
            </div>
