        <div id="tab-minori" class="tab-content">
            <div class="data-row" style="display: block;">
                <div style="display: flex; justify-content: space-between; margin-bottom: 4px;">
                    <span class="data-label" style="color: var(--sys-glow);"><i class="fas fa-battery-full"></i> 实体化能量:</span>
                    <span class="data-value" style="color: #fff;"><span id="val-mood">--</span> | <span id="val-energy">0</span>%</span>
                </div>
                <div class="bar-container" style="border-color: var(--sys-glow);"><div class="energy-bar" id="ui-energy-bar" style="width: 100%;"></div></div>
            </div>
            <div style="background: rgba(0,0,0,0.4); border-left: 4px solid var(--minori-pink); padding: 12px; margin-top: 12px;">
                <div style="font-size: 11px; color: var(--sys-glow); margin-bottom: 6px; font-weight: bold;">悄悄话：</div>
                <div style="font-style: italic; color: #fff;">"<span id="val-advice">--</span>"</div>
            </div>

            <div id="companion-section" style="display: none; margin-top: 15px;">
                <div class="data-label" style="border-bottom: 1px solid rgba(255,105,180,0.3); padding-bottom: 4px;">👑 羁绊名册</div>
                <div id="val-companions" style="font-size: 12px; line-height: 1.5; margin-top: 5px;"></div>
            </div>

            <!-- 新增：音乐播放器 -->
            <div style="margin-top: 15px; background: rgba(0,0,0,0.4); padding: 12px; border-radius: 8px; border: 1px solid rgba(255, 105, 180, 0.4); box-shadow: inset 0 0 10px rgba(255, 20, 147, 0.1);">
