                        <button id="btn-play-song" class="music-btn" style="border-color: var(--sys-glow);" title="播放/暂停"><i class="fas fa-play"></i></button>
                        <button id="btn-next-song" class="music-btn" title="下一首"><i class="fas fa-step-forward"></i></button>
                    </div>
                </div>
                <!-- 隐藏的音频组件 -->
                <audio id="minori-bgm" preload="none"></audio>
            </div>
        </div>

        <div id="tab-dice" class="tab-content">
