                <option value="火力压制 (合体技/解围)">💥 战斗：火力压制与解围</option>
                <option value="紧急治疗 (治愈/保护)">💖 辅助：紧急治疗与保护</option>
                <option value="情报分析 (黑客/破解)">🧠 智力：情报分析与破解</option>
                <option value="肉体补魔 (亲密恢复/安抚)">💋 亲密：肉体补魔与安抚</option>
            </select>

