    <script type="module">
        (function () {
            if (typeof getAllVariables !== 'function' || typeof _ === 'undefined') return;
            const vars = getAllVariables();
            const getV = (path, fallback) => _.get(vars, 'stat_data.' + path, fallback);

            window.dndAttrs = {
                str: Number(getV('str', 10)), dex: Number(getV('dex', 10)), con: Number(getV('con', 10)),
                int: Number(getV('int', 10)), wis: Number(getV('wis', 10)), cha: Number(getV('cha', 10))
            };

            const calcMod = (val) => Math.floor((val - 10) / 2);
            const formatMod = (mod) => mod >= 0 ? `+${mod}` : `${mod}`;

            document.getElementById('val-location').textContent = getV('current_location', '主神广场');
            document.getElementById('val-timer').textContent = getV('mission_timer', '无任务');
            document.getElementById('val-rp').textContent = getV('reward_points', 0);

            const safeName = getV('char_name', '待设定');
            document.getElementById('val-char-name').textContent = safeName;

            const currentLevel = Number(getV('level', 1));
            document.getElementById('val-level').textContent = currentLevel;
            document.getElementById('val-class').textContent = getV('class_name', '新人');

            const expCur = Number(getV('current_xp', 0));
            const expMax = Number(getV('max_xp', currentLevel * 100));
            document.getElementById('val-exp-cur').textContent = expCur;
            document.getElementById('val-exp-max').textContent = expMax;
            document.getElementById('ui-exp-bar').style.width = Math.max(0, Math.min(100, (expCur / (expMax || 1)) * 100)) + '%';

            const hpCur = Number(getV('hp_current', 10)); const hpMax = Number(getV('hp_max', 10));
            document.getElementById('val-hp-cur').textContent = hpCur;
            document.getElementById('val-hp-max').textContent = hpMax;
            document.getElementById('ui-hp-bar').style.width = Math.max(0, Math.min(100, (hpCur / (hpMax || 1)) * 100)) + '%';
            document.getElementById('val-status-effects').textContent = getV('status_effects', '正常');

            ['str', 'dex', 'con', 'int', 'wis', 'cha'].forEach(attr => {
                const val = window.dndAttrs[attr];
                const elVal = document.getElementById(`val-${attr}`); const elMod = document.getElementById(`mod-${attr}`);
                if (elVal) elVal.textContent = val; if (elMod) elMod.textContent = formatMod(calcMod(val));
            });

            document.getElementById('val-ac').textContent = getV('ac', 10);
            document.getElementById('val-weapon').textContent = getV('weapon_main', '空手');
            document.getElementById('val-armor').textContent = getV('armor_name', '新手作训服');
            ['d','c','b','a','s'].forEach(r => document.getElementById(`val-${r}`).textContent = getV(`side_story_${r}`, 0));

            document.getElementById('val-mood').textContent = getV('mood', '兴奋');
            const energy = Number(getV('energy', 100));
            document.getElementById('val-energy').textContent = energy;
            document.getElementById('ui-energy-bar').style.width = Math.max(0, Math.min(100, energy)) + '%';
            document.getElementById('val-advice').textContent = getV('minori_advice', '主人加油！');

            const companionsHtml = getV('companions_html', '');
            if (companionsHtml && companionsHtml.trim() !== '') {
                document.getElementById('companion-section').style.display = 'block';
                document.getElementById('val-companions').innerHTML = companionsHtml;
            }

            const tabBtns = document.querySelectorAll('.tab-btn');
            const tabContents = document.querySelectorAll('.tab-content');

            tabBtns.forEach(btn => {
                btn.addEventListener('click', (e) => {
                    e.stopPropagation();
                    tabBtns.forEach(b => b.classList.remove('active'));
                    tabContents.forEach(c => c.classList.remove('active'));
                    btn.classList.add('active');
                    document.getElementById(btn.getAttribute('data-tab')).classList.add('active');
                });
            });

            ['dice-action', 'dice-dc', 'dice-attr', 'harem-name', 'harem-type'].forEach(id => {
                const el = document.getElementById(id);
                if(el) el.addEventListener('click', e => e.stopPropagation());
            });

            function showToast(msg) {
                const t = document.getElementById('toast-msg');
                t.innerHTML = `<i class="fas fa-bell"></i> ${msg}`;
                t.classList.add('show'); setTimeout(() => t.classList.remove('show'), 2000);
            }

            function copyToInput(text) {
                try {
                    if (window.parent && window.parent.$) {
                        const $ta = window.parent.$('#send_textarea');
                        if ($ta.length > 0) {
                            $ta.val(text);
                            $ta[0].dispatchEvent(new Event('input', { bubbles: true }));
                            showToast('指令已载入输入框~可以继续修改哦！');
                            return;
                        }
                    }
                    const ta = document.getElementById('send_textarea') || document.querySelector('#chat_input');
                    if(ta) {
                        ta.value = text;
                        ta.dispatchEvent(new Event('input', { bubbles: true }));
                        showToast('指令已载入输入框~可以继续修改哦！');
                    }
                } catch (e) { showToast('发生小错误...'); }
            }

            function sendDirectly(text) {
                try {
                    let inputEl, sendBtn;

                    if (window.parent && window.parent.document) {
                        inputEl = window.parent.document.getElementById('send_textarea') || window.parent.document.querySelector('#chat_input');
                        sendBtn = window.parent.document.getElementById('send_but');
                    }

                    if (!inputEl) {
                        inputEl = document.getElementById('send_textarea') || document.querySelector('#chat_input');
                        sendBtn = document.getElementById('send_but');
                    }

                    if (inputEl && sendBtn) {
                        const nativeInputValueSetter = Object.getOwnPropertyDescriptor(window.HTMLTextAreaElement.prototype, 'value').set;
                        if(nativeInputValueSetter) {
                            nativeInputValueSetter.call(inputEl, text);
                        } else {
                            inputEl.value = text;
                        }

                        inputEl.dispatchEvent(new Event('input', { bubbles: true }));
                        inputEl.dispatchEvent(new Event('change', { bubbles: true }));

                        setTimeout(() => {
                            sendBtn.click();
                            showToast('骰子已直接掷出！不可反悔哦~');
                        }, 100);

                    } else {
                        showToast('找不到发送框或发送按钮呢...');
                    }
                } catch (e) {
                    console.error(e);
                    showToast('发送时发生了一点小错误...');
                }
            }

            document.querySelectorAll('.action-trigger').forEach(btn => {
                btn.addEventListener('click', () => { copyToInput(btn.getAttribute('data-action')); });
            });

            // ====== 音乐播放器逻辑 ======
            const playlist = [
                { title: '羁绊电波 - 中文柔情版', src: 'https://files.catbox.moe/s2lvae.mp3' },
                { title: '羁绊电波 - 英文律动版', src: 'https://files.catbox.moe/lfjlok.mp3' }
            ];
            let currentSongIndex = 0;
            let isPlaying = false;

            const audioEl = document.getElementById('minori-bgm');
            const btnPlay = document.getElementById('btn-play-song');
            const btnPrev = document.getElementById('btn-prev-song');
            const btnNext = document.getElementById('btn-next-song');
            const titleEl = document.getElementById('music-title');
            const indicatorEl = document.getElementById('music-indicator');

            function loadSong(index) {
                audioEl.src = playlist[index].src;
                titleEl.textContent = playlist[index].title;
                updateIndicator();
            }

            function updateIndicator() {
                const status = isPlaying ? "正在播放" : "已暂停";
                indicatorEl.textContent = `${status} - ${currentSongIndex + 1}/${playlist.length}`;
            }

            function togglePlay() {
                if (isPlaying) {
                    audioEl.pause();
                    btnPlay.innerHTML = '<i class="fas fa-play"></i>';
                } else {
                    // 如果网络不佳，play() 可能会抛出异常被 catch
                    audioEl.play().catch(e => showToast("播放失败，可能是网络未连接哦..."));
                    btnPlay.innerHTML = '<i class="fas fa-pause"></i>';
                }
                isPlaying = !isPlaying;
                updateIndicator();
            }

            function nextSong() {
                currentSongIndex = (currentSongIndex + 1) % playlist.length;
                loadSong(currentSongIndex);
                if (isPlaying) audioEl.play().catch(e => {});
            }

            function prevSong() {
                currentSongIndex = (currentSongIndex - 1 + playlist.length) % playlist.length;
                loadSong(currentSongIndex);
                if (isPlaying) audioEl.play().catch(e => {});
            }

            // 初始化加载第一首
            loadSong(currentSongIndex);

            // 绑定事件
            btnPlay.addEventListener('click', (e) => { e.stopPropagation(); togglePlay(); });
            btnNext.addEventListener('click', (e) => { e.stopPropagation(); nextSong(); });
            btnPrev.addEventListener('click', (e) => { e.stopPropagation(); prevSong(); });

            // 自动循环：播放完毕自动切下一首
            audioEl.addEventListener('ended', () => {
                nextSong();
            });
            // =========================


            document.getElementById('btn-roll-dice').addEventListener('click', function() {
                const action = document.getElementById('dice-action').value.trim();
                const attrKey = document.getElementById('dice-attr').value;
                const dc = parseInt(document.getElementById('dice-dc').value) || 10;

                if (!action) { showToast('主人，你还没说要做什么呢！'); return; }

                const $btn = this;
                if ($btn.disabled) return;

                $btn.disabled = true;
                $btn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Minori 算力全开...';

                const overlay = document.getElementById('dice-anim-overlay');
                const animNum = document.getElementById('anim-number');
                const animSub = document.getElementById('anim-subtitle');

                animSub.textContent = 'Minori 疯狂运算中...';
                animNum.style.color = '#fff';
                animNum.style.textShadow = '0 0 8px var(--minori-pink)';
                overlay.classList.add('show');

                let ticks = 0;
                const interval = setInterval(() => {
                    animNum.textContent = Math.floor(Math.random() * 20) + 1;
                    ticks++;

                    if (ticks >= 20) {
                        clearInterval(interval);

                        const attrVal = window.dndAttrs[attrKey] || 10;
                        const mod = calcMod(attrVal);
                        const d20 = Math.floor(Math.random() * 20) + 1;
                        const total = d20 + mod;
                        let result = '';

                        if (d20 === 1) result = '大失败';
                        else if (d20 === 20) result = '大成功';
                        else if (total >= dc) result = '成功';
                        else result = '失败';

                        animNum.textContent = d20;
                        if (d20 === 20) {
                            animNum.style.color = 'var(--gold)';
                            animNum.style.textShadow = '0 0 15px var(--gold)';
                            animSub.textContent = '✨ 大成功！主人好厉害！ ✨';
                        } else if (d20 === 1) {
                            animNum.style.color = 'var(--sys-danger)';
                            animNum.style.textShadow = '0 0 8px var(--sys-danger)';
                            animSub.textContent = '⚠️ 糟糕！呜...大失败...';
                        } else if (total >= dc) {
                            animSub.textContent = '💖 判定成功啦！';
                        } else {
                            animNum.style.color = '#aaa';
                            animNum.style.textShadow = 'none';
                            animSub.textContent = '💦 呜...差一点点...';
                        }

                        const attrName = document.querySelector(`#dice-attr option[value="${attrKey}"]`).innerText;
                        const msg = `<DND5E判定_Minori辅算>\n🎲 1d20(${d20}) ${formatMod(mod)}(${attrName}) = ${total}\n主人行动：${action}\n主神难度(DC)：${dc}\nMinori判定结果：${result}\n</DND5E判定_Minori辅算>`;

                        setTimeout(() => {
                            sendDirectly(msg);
                            document.getElementById('dice-action').value = '';
                            overlay.classList.remove('show');
                            $btn.disabled = false;
                            $btn.innerHTML = '<i class="fas fa-dice-d20"></i> 执行强行判定';
                        }, 1500);
                    }
                }, 40);
            });

            const haremModal = document.getElementById('harem-modal');
            document.getElementById('btn-open-harem').addEventListener('click', () => {
                haremModal.style.display = 'flex';
            });
            document.getElementById('btn-close-harem').addEventListener('click', () => {
                haremModal.style.display = 'none';
            });
            document.getElementById('btn-send-harem').addEventListener('click', () => {
                const name = document.getElementById('harem-name').value.trim();
                const type = document.getElementById('harem-type').value;
                if (!name) { showToast('主人，你还没写老婆的名字呢！'); return; }

                const msg = `[非法指令] Minori！立刻黑掉主神的监控防火墙！把我藏在私人空间里的【${name}】以数据流的形式强行投影到我身边！\n【最高优先级需求】：${type}\n(注：此行为属严重作弊，请详细描写她突然降临的惊艳感、突破位面壁垒的特效、以及她对主人的绝对服从与保护欲。)`;

                copyToInput(msg);
                haremModal.style.display = 'none';
            });
        })();
    </script>
