    <script>
        (function() {
            const currentScript = document.currentScript;
            const context = currentScript.parentElement;

            const optionsDataSource = context.querySelector('.options-data-source');
            const container = context.querySelector('.button-group-final');

            if (!optionsDataSource || !container) return;

            const optionsText = optionsDataSource.innerHTML;
            const lines = optionsText.trim().split('\n');

            container.innerHTML = '';

            // 强效剪贴板兼容函数
            async function fallbackCopyTextToClipboard(text) {
                var textArea = document.createElement("textarea");
                textArea.value = text;
                textArea.style.top = "0";
                textArea.style.left = "0";
                textArea.style.position = "fixed";
                document.body.appendChild(textArea);
                textArea.focus();
                textArea.select();
                try {
                    var successful = document.execCommand('copy');
                    return successful;
                } catch (err) {
                    console.error('Fallback: Oops, unable to copy', err);
                    return false;
                } finally {
                    document.body.removeChild(textArea);
                }
            }

            async function copyTextToClipboard(text) {
                if (!navigator.clipboard) {
                    return await fallbackCopyTextToClipboard(text);
                }
                try {
                    await navigator.clipboard.writeText(text);
                    return true;
                } catch (err) {
                    console.error('Async: Could not copy text: ', err);
                    return await fallbackCopyTextToClipboard(text);
                }
            }

            lines.forEach(line => {
                const trimmedLine = line.trim();
                if (!trimmedLine || !trimmedLine.includes('|')) return;

                const parts = trimmedLine.split('|').map(s => s.trim());
                if(parts.length < 4) return;
                const [title, attr, dc, desc] = parts;

                const button = document.createElement('div');
                button.className = 'action-btn-final';

