                const chatInputText = `亲爱的，我想尝试这个路线：${desc} (属性判定:${attr.toUpperCase()}, 难度DC:${dc})`;

                button.addEventListener('click', async (event) => {
                    event.stopPropagation();

                    // 1. 强制复制到系统剪贴簿
                    const copySuccess = await copyTextToClipboard(clipboardText);

                    // 2. 视觉反馈
                    const originalHTML = button.innerHTML;
