                        button.innerHTML = `<i class="fas fa-check-circle"></i> 已复制！快去状态栏右键粘贴吧~`;
                    } else {
                        button.innerHTML = `<i class="fas fa-exclamation-circle"></i> 复制失败，请手动输入哦...`;
                    }

                    setTimeout(() => {
                        button.classList.remove('copied');
                        button.innerHTML = originalHTML;
                    }, 2000);

